// Output 1: slider value (immediate brightness)
// Output 2: dimmer #1 DIM command (dawn/dusk ramps, range 0-40)
// Output 3: dimmer #2 DIM command (midday ramps, range 40-60)
//
// Uses PARTIAL start so ramp finishes on time even after mid-ramp reboot.
// Dimmer t ranges 0.0-1.0; step=1/steps per tick.
// Upward ramps: t goes 0→1, so start = elapsed fraction
// Downward ramps: t goes 1→0, so start = 1 - elapsed fraction

var now = new Date();
var minutes = now.getHours() * 60 + now.getMinutes();

var brightness = 0;
var dimmer1Msg = null;
var dimmer2Msg = null;

if (minutes >= 390 && minutes < 420) {
    // 06:30-07:00: dawn ramp 0→40 (dimmer #1, t: 0→1)
    var elapsed = (minutes - 390) / 30;
    brightness = Math.round(elapsed * 40);
    dimmer1Msg = {payload: {command: "DIM", target: 1.0, start: elapsed}};
} else if (minutes >= 420 && minutes < 660) {
    // 07:00-11:00: stable 40
    brightness = 40;
} else if (minutes >= 660 && minutes < 690) {
    // 11:00-11:30: midday ramp 40→60 (dimmer #2, t: 0→1)
    var elapsed = (minutes - 660) / 30;
    brightness = 40 + Math.round(elapsed * 20);
    dimmer2Msg = {payload: {command: "DIM", target: 1.0, start: elapsed}};
} else if (minutes >= 690 && minutes < 780) {
    // 11:30-13:00: stable 60
    brightness = 60;
} else if (minutes >= 780 && minutes < 810) {
    // 13:00-13:30: midday ramp 60→40 (dimmer #2, t: 1→0)
    var elapsed = (minutes - 780) / 30;
    brightness = 60 - Math.round(elapsed * 20);
    dimmer2Msg = {payload: {command: "DIM", target: 0.0, start: 1.0 - elapsed}};
} else if (minutes >= 810 && minutes < 1170) {
    // 13:30-19:30: stable 40
    brightness = 40;
} else if (minutes >= 1170 && minutes < 1200) {
    // 19:30-20:00: dusk ramp 40→0 (dimmer #1, t: 1→0)
    var elapsed = (minutes - 1170) / 30;
    brightness = 40 - Math.round(elapsed * 40);
    dimmer1Msg = {payload: {command: "DIM", target: 0.0, start: 1.0 - elapsed}};
}

