// Calculate Saturated Vapor Pressure (SVP) in kPa
// Formula: SVP = 0.6108 * exp(17.27 * T / (T + 237.3))
const svp = 0.6108 * Math.exp((17.27 * temp) / (temp + 237.3));

// Calculate Actual Vapor Pressure (AVP) in kPa
const avp = svp * (humidity / 100);

