// GAIN SCHEDULING: Kp and Kd scale down near target to prevent oscillation.
//   |error| >= 4%: full gains (aggressive response to large deviations)
//   |error| <= 1.5%: gains reduced to 15% (smooth, gentle control)
//   Between: linear interpolation

const manualMode = flow.get('manual_fan_mode');
