// PID tuning - adjustable via UI text input (Kp,Ki,Kd)
const tuning = flow.get('pid_tuning') || { Kp: 15, Ki: 0.08, Kd: 8 };

// PID state
let pid = flow.get('pid_values') || {
    integral: 0,
    lastError: 0,
    lastTime: Date.now(),
    filteredDeriv: 0
};

const now = Date.now();
const dt = (now - pid.lastTime) / 1000;

// Guard: skip if dt is zero or unreasonably large (restart/gap)
if (dt <= 0 || dt > 120) {
    pid.lastTime = now;
    flow.set('pid_values', pid);
    node.status({ fill: "grey", shape: "ring", text: "Waiting for next cycle" });
    return null;
}

const error = -humidityDiff;
const absError = Math.abs(error);

// === GAIN SCHEDULING ===
// Scale Kp and Kd based on error magnitude to prevent oscillation near target
const NEAR_THRESH = 1.5;  // below this: minimum gain (gentle)
const FAR_THRESH = 4.0;   // above this: full gain (aggressive)
const MIN_GAIN = 0.15;    // floor: 15% of full gain when near target
const gainFactor = Math.min(1.0, Math.max(MIN_GAIN,
    MIN_GAIN + (1.0 - MIN_GAIN) * (absError - NEAR_THRESH) / (FAR_THRESH - NEAR_THRESH)));

// === PROPORTIONAL (gain-scheduled) ===
const P = tuning.Kp * gainFactor * error;

// === INTEGRAL with anti-windup ===
pid.integral += error * dt;

// Clamp integral contribution to ±120 PWM worth
const I_MAX = 120 / Math.max(tuning.Ki, 0.001);
pid.integral = Math.max(-I_MAX, Math.min(I_MAX, pid.integral));

// Decay integral when error is small (prevents creep after humidity spike)
if (absError < 2.0) {
    pid.integral *= (1 - 0.05 * dt); // 5% decay per second near target
}

const I = tuning.Ki * pid.integral;

// === DERIVATIVE with exponential low-pass filter (gain-scheduled) ===
const rawDeriv = (error - pid.lastError) / dt;
const alpha = 0.12; // heavier filter than before (was 0.25) to reduce noise
pid.filteredDeriv = alpha * rawDeriv + (1 - alpha) * (pid.filteredDeriv || 0);
const D = tuning.Kd * gainFactor * pid.filteredDeriv;

// === TOTAL PID OUTPUT ===
const pidOutput = P + I + D;

// Map to fan speed: base speed (resting circulation) + PID adjustment
const BASE_SPEED = 50;
let fanSpeed = BASE_SPEED + pidOutput;

// Clamp to valid PWM range
const MIN_SPEED = 40;
const MAX_SPEED = 230;
fanSpeed = Math.max(MIN_SPEED, Math.min(MAX_SPEED, Math.round(fanSpeed)));

// Smooth transitions: limit rate of change
