    const maxChange = Math.min(20, Math.max(8, absError * 2));
    const delta = fanSpeed - lastSpeed;
    if (Math.abs(delta) > maxChange) {
        fanSpeed = Math.round(lastSpeed + Math.sign(delta) * maxChange);
    }
}

