node.status({
    fill: color, shape: "dot",
    text: dir + " Δ" + humidityDiff.toFixed(1) + "% → " + pct + "% [P:" + P.toFixed(0) + " I:" + I.toFixed(0) + " D:" + D.toFixed(0) + " g:" + gainFactor.toFixed(2) + "]"
