    var val = parseInt(line.substring(4));
    if (!isNaN(val)) {
        return [null, {payload: val, topic: "door_left"}, null, null];
    }
} else if (line.startsWith("D24,")) {
    var val = parseInt(line.substring(4));
    if (!isNaN(val)) {
        return [null, null, {payload: val, topic: "door_right"}, null];
    }
